css:
@charset "UTF-8";
/* CSS Document */
/* Variables */
/* Colors */
@import url("https://cdn.jsdelivr.net/npm/bootstrap-icons@1.8.1/font/bootstrap-icons.css");
@import url("fonts/founders-grotesk.css");
.blue {
  color: #1ea0ff;
}

/* ATENÇÃO: artefact img vh calc values are hard coded, update if changed  */
/* @media skeleton */
/* Bootstrap Icons */
/* Fonts */
@font-face {
  font-family: "Tiempos Text";
  font-weight: 400;
  font-style: normal;
  src: url("/fonts/tiempos-text-regular.woff2") format("woff");
}
@font-face {
  font-family: "Tiempos Text";
  font-weight: 600;
  font-style: normal;
  src: url("/fonts/tiempos-text-semibold.woff2") format("woff");
}
@font-face {
  font-family: "Tiempos Text";
  font-weight: 400;
  font-style: italic;
  src: url("/fonts/tiempos-text-regular-italic.woff2") format("opentype");
}
@font-face {
  font-family: "Tiempos Text";
  font-weight: 600;
  font-style: italic;
  src: url("/fonts/tiempos-text-semibold-italic.woff2") format("opentype");
}
/* Founders Grotesk, Tiempos, Inter */
:root {
  font-family: Inter, sans-serif;
  font-feature-settings: "liga" 1, "calt" 1; /* fix for Chrome */
}

@supports (font-variation-settings: normal) {
  :root {
    font-family: InterVariable, sans-serif;
  }
}
/* General */
body {
  font-family: "Tiempos Text", serif;
  font-weight: 400;
  font-size: 16px;
  line-height: 1;
  font-variant-numeric: oldstyle-nums;
  -webkit-font-smoothing: auto;
  background-color: #e4e4e4;
  color: black;
}

img {
  max-width: 100%;
}

a,
a:hover {
  text-decoration: none;
  color: black;
}

/* General Typography */
.about-text blockquote {
  font-size: 0.8rem;
  margin-bottom: 1.5rem;
  width: 86%;
  line-height: 1.6;
}

.post-text a,
a.text.cat-link {
  font-family: "Tiempos Text", serif;
  font-weight: 600;
  text-decoration: none;
}

.post-text blockquote {
  font-size: 0.8em;
  line-height: 24px;
  margin-left: 45px;
  width: 75%;
  text-align: justify;
}

.capitalize {
  text-transform: capitalize;
}

p.about-sol {
  font-family: "Tiempos Text", serif;
  font-weight: 400;
  font-size: 20px;
  line-height: 1.6;
  color: black;
}
@media (min-width: 576px) {
  p.about-sol {
    font-size: 22px;
    letter-spacing: -0.2px;
  }
}
.cta-about-browse-all {
  display: inline-block;
  font-family: "degular-mono";
  font-weight: 400;
  font-size: 16px;
  letter-spacing: -0.5px;
  padding-top: 8px;
  padding-bottom: 2px;
  border-bottom: 2px solid;
}
.cta-about-browse-all:hover {
  color: #e16640;
  transition: color 0.2s ease-in;
}

.prev-next-label {
  display: block;
  font-family: "degular-mono", sans;
  font-size: 14px;
  line-height: 20px;
  font-weight: 500;
  margin-bottom: 6px;
  letter-spacing: -0.5px;
}

.artefact-count-deet,
.related,
.para-text,
.filter-title,
.faux-table.db,
.faux-table-head-row,
.sub-header-col.baoff,
.back-office {
  font-family: "degular-mono", sans-serif;
  font-weight: 400;
  font-size: 14px;
  letter-spacing: normal;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}

.a-module-deets,
.artefact.count,
.cat-count {
  font-family: "Tiempos Text", sans-serif;
  font-weight: 400;
  font-size: 13px;
  letter-spacing: normal;
  line-height: 20px;
  -webkit-font-smoothing: antialiased;
}

.a-module-deets,
.artefact.count {
  display: block;
}

/* DATUM */
@media (min-width: 768px) {
  .datum-left-col.year {
    text-align: right;
  }
}

.datum-row {
  padding-top: 10px;
}
@media (min-width: 576px) {
  .datum-row.artefact-deets-row {
    padding-top: 6px;
  }
}

.datum-row.cat-about {
  padding-top: 30px;
  padding-bottom: 30px;
}

.container-md.page.faq-about {
  padding-bottom: 60px;
}

.datum-row.faq-about {
  padding-top: 30px;
}

.datum-row.resource.last {
  padding-bottom: 60px;
}

.datum-row.related-end-spacer {
  padding-bottom: 60px;
}

.datum-section.title.faq-about {
  padding-bottom: 90px;
}

.container-md.post-body, .container-md.post-gallery-body {
  padding-bottom: 60px;
}

/* Datum Section & */
.datum-section {
  padding-top: 15px;
}
.datum-section.top-border {
  border-top: 1px solid #cccccc;
}
.datum-section.title {
  padding-top: 15px;
  padding-bottom: 5px;
}
.datum-section.allcats {
  padding-top: 0px;
}
.datum-section.feature-img {
  padding-top: 30px;
}
.datum-section.deets {
  padding-top: 30px;
}
.datum-section.about {
  padding-top: 60px;
  padding-bottom: 90px;
}
.datum-section.timeline, .datum-section.related, .datum-section.resources {
  padding-top: 20px;
}
.datum-section.sources {
  padding-top: 20px;
  padding-bottom: 60px;
}
.datum-section.more-info {
  padding-top: 20px;
  padding-bottom: 60px;
}
.datum-section.prev-next {
  padding-top: 20px;
  padding-bottom: 45px;
}
.datum-section.md {
  padding-top: 60px;
}
.datum-section.sm {
  padding-top: 30px;
}
.datum-section.post-body, .datum-section.post-gallery-body, .datum-section.none {
  padding-top: 60px;
}
.datum-section.post-lead {
  padding-bottom: 60px;
}
.datum-section.cat-artefacts {
  padding-top: 30px;
  padding-bottom: 45px;
}
.datum-section.post-artefacts {
  padding-top: 30px;
  padding-bottom: 60px;
}
.datum-section.footer-quote {
  padding-top: 120px;
  padding-bottom: 120px;
}
.datum-section.footer-icons {
  padding-top: 34px;
  padding-bottom: 2px;
}
.datum-section.footer-logos {
  padding-top: 60px;
  padding-bottom: 60px;
  text-align: center;
}
.datum-section.decade, .datum-section.origin, .datum-section.discipline, .datum-section.format, .datum-section.subtag {
  padding-top: 8px;
  padding-bottom: 4px;
  border-top: 1px solid black;
}
.datum-section.subtag {
  padding-bottom: 8px;
}
.datum-section.page-not-found {
  padding-bottom: 90px;
}
.datum-section.short-link {
  padding-bottom: 30px;
}

.datum-row.timeline-row.last {
  padding-bottom: 60px;
}

h3.title.datum-title {
  font-weight: 600;
  letter-spacing: -0.5px;
  padding-top: 0px;
}
h3.title.datum-title.about {
  padding-top: 5px;
}
h3.title.datum-title.cat-artefacts {
  padding-top: 0px;
  margin-top: -5px;
}

/* to align with H3 */
