}
.deet-links,
.datum-left-col,
.related-links {
  color: black;
  font-family: "degular-mono", sans;
  font-size: 14px;
  line-height: 20px;
  letter-spacing: -0.5px;
}
@media (min-width: 576px) {
  .timeline-value {
    padding-top: 4px;
  }
}
.cat-label {
  font-family: "degular-mono";
  font-weight: 400;
  font-size: 14px;
  line-height: 18px;
  letter-spacing: -0.5px;
  margin-top: 46px;
  margin-bottom: 0px;
}
.cat-label.artefact {
  margin-top: 11px;
}

h2 .artefact.count {
  vertical-align: 120%;
}

.cat-count {
  font-weight: 400;
  margin-left: 3px;
  margin-right: 1px;
}
.cat-count.fake {
  opacity: 0;
  cursor: default;
}
@media (min-width: 992px) {
  .cat-count {
    font-size: 11px;
    vertical-align: super;
  }
}

.cat-count.origin,
.cat-count.discipline,
.cat-count.format {
  font-size: 11px;
  vertical-align: super;
}
@media (min-width: 576px) {
  .cat-count.origin,
  .cat-count.discipline,
  .cat-count.format {
    font-size: 13px;
  }
}
.cat-count.tags {
  font-weight: 400;
  font-size: 0.6rem;
  vertical-align: 100%;
  margin-left: 2px;
}

.post-meta,
.post-text figcaption,
.caption {
  font-family: "degular-mono", sans-serif;
  font-size: 13px;
  line-height: 1.5;
}

section.about {
  font-size: 16px;
  line-height: 1.6;
  margin-top: 2rem;
}

/* Random Stuff (arrumar) */

.wip-badge {
  font-family: "degular-mono", sans-serif;
  font-size: 12px;
  font-weight: 300;
  background-color: black;
  padding: 7px 8px 8px 8px;
  margin-top: 15px;
  margin-left: -1px;
}

.more-images-badge {
  font-family: "degular-mono", sans-serif;
  font-size: 12px;
  font-weight: 300;
  background-color: coral;
  padding: 7px 8px 8px 8px;
  margin-top: 15px;
  margin-left: 3px;
}

.card-body p.para-text {
  margin-bottom: 0;
  max-width: 80%;
}

.caption.a-multi {
  color: white;
}

.more-info-text {
  font-family: "degular-mono", sans;
  font-size: 14px;
  letter-spacing: -0.5px;
  line-height: 1.4;
  padding-top: 0px;
}
@media (min-width: 576px) {
  .more-info-text {
    max-width: 400px;
  }
}

.more-info-text p.para-text {
  margin-bottom: 0px;
}

/* HEADER */
.container-header {
  padding-bottom: 0;
  z-index: 1000;
  overflow: hidden;
}
@media (min-width: 1200px) {
  .container-header {
    height: 40px;
  }
}

.header-row {
  margin-right: -15px;
}

.title-col {
  height: 63px;
  position: relative;
}

h1.site-title {
  font-family: "Founders Grotesk Condensed", sans;
  font-size: 18px;
  line-height: 18px;
  letter-spacing: normal;
  font-weight: 600;
  display: inline-block;
  color: black;
  margin-top: 7px;
  margin-bottom: 2px;
}
@media (min-width: 992px) {
  h1.site-title {
    font-size: 26px;
    line-height: 26px;
    margin-top: 4px;
  }
}

h1.site-title a {
  text-decoration: none;
}

h1.site-title a:hover {
  display: inline;
  color: black;
}

.sub-header-link {
  font-family: "degular-mono", sans;
  display: inline-block;
  font-size: 12px;
  line-height: 15px;
  font-weight: 400;
  letter-spacing: -0.5px;
  text-transform: uppercase;
  color: black;
  width: auto;
  text-align: center;
  transition: 0.2s;
  text-decoration: none;
  margin-right: 8px;
}
.sub-header-link:hover {
  color: coral;
  text-decoration: none;
}
@media (min-width: 768px) {
  .sub-header-link {
    font-size: 14px;
    line-height: 31px;
  }
}
.nav-col {
  padding-top: 4px;
}

