@keyframes color-to-color {
  12% {
    fill: #c47900;
  }
  25% {
    fill: #e16640;
  }
  37% {
    fill: #f2b34b;
  }
  50% {
    fill: #93a64e;
  }
  62% {
    fill: #2eb5b0;
  }
  75% {
    fill: #4f9dd3;
  }
  87% {
    fill: #d8709c;
  }
  100% {
    fill: #995488;
  }
}
@keyframes gradient {
  0% {
    background-position: 0% 0;
  }
  50% {
    background-position: 100% 100%;
  }
  100% {
    background-position: 0 0;
  }
}

/* Sub Header(s) (Navigation) */

.sub-header-col {
  max-height: 0px;
  padding-left: 0;
  padding-right: 0;
  text-align: center;
  position: relative;
}
@media (min-width: 576px) {
  .sub-header-col {
    height: 30px;
  }
}
@media (min-width: 768px) {
  .sub-header-col {
    max-height: 100%;
    height: 40px;
  }
}
@media (min-width: 992px) {
  .sub-header-col {
    height: 32px;
  }
}
@media (min-width: 1200px) {
  .sub-header-col {
    height: 40px;
  }
}

.artefacts-bottom-sub-header-bg {
  background-color: black;
}

.col-baoff.active {
  background-color: #e16640;
}

.col-baoff.odd {
  background-color: #e4e4e4;
}

.col-baoff.even {
  background-color: #ebebeb;
}

.sub-header-link.baoff {
  color: #000;
}

.sub-header-link.baoff:hover {
  color: #e16640;
}

.col-baoff.active .sub-header-link.baoff:hover {
  color: #ebebeb;
}

/* H Footer */

.footer-row {
  padding-top: 30px;
  padding-bottom: 30px;
}

.footer-col {
  margin-bottom: 15px;
}
@media (min-width: 576px) {
