  */
}
.footer-link.cat {
  font-family: "Founders Grotesk Condensed", sans;
  font-size: 19px;
  font-weight: 800;
  letter-spacing: 0.2px;
  line-height: 28px;
  text-transform: uppercase;
}
.footer-link.cat:hover {
  color: #000;
  border-bottom: none;
}
.footer-link.primary {
  font-weight: 600;
}
.footer-link:hover {
  text-decoration: none;
  border-bottom: 1.5px solid;
}

.container-fluid.footer-icons {
  background-color: #f5f5f5;
  color: #1a1a1a;
}

.container-fluid.footer-quote,
