  }
}

.sunny {
  margin-left: 30px;
}

q.footer-quote {
  font-family: "Tiempos Text";
  font-weight: 400;
  font-size: 40px;
  line-height: 1.2;
  quotes: "«" "»";
}

p.footer-quote-byline {
  font-family: "Tiempos Text";
  font-size: 16px;
  padding-top: 24px;
}

.footer-icon {
  text-align: center;
  height: 140px;
  padding: 0px 10px;
  transition: 0.1s ease-in-out;
}

.footer-icon-link:hover .footer-icon {
  filter: none;
}

.footer-icon-col {
  padding-bottom: 30px;
}

/* Footer Icon Hover Styles */
a > h3.section-title.allcats {
  color: #000;
}

/* Containers */

.container-artefacts-1 {
  background-color: black;
  padding-top: 15px;
  padding-left: 15px;
  padding-right: 15px;
}

.container-artefacts-2 {
  background-color: black;
  padding-top: 8px;
}

.container-artefacts-index {
  background-color: black;
  padding-top: 8px;
  max-height: calc(100vh - 96px);
  overflow: hidden;
}
@media (min-width: 576px) {
  .container-artefacts-index {
    max-height: calc(100vh - 70px);
  }
}
@media (min-width: 768px) {
  .container-artefacts-index {
    max-height: calc(100vh - 80px);
  }
}
@media (min-width: 992px) {
  .container-artefacts-index {
